import { handle } from '../lib/handler.js';
import { PAGE } from '../lib/page.js';

// PWA static assets embedded as base64
const ASSETS = {
  "/manifest.json": { b64: "", ct: "application/json" },
  "/sw.js": { b64: "", ct: "application/javascript" },
  "/favicon.ico": { b64: "", ct: "image/x-icon" },
  "/icons/favicon-32x32.png": { b64: "", ct: "image/png" },
  "/icons/apple-touch-icon.png": { b64: "", ct: "image/png" },
  "/icons/icon-72x72.png": { b64: "", ct: "image/png" },
  "/icons/icon-96x96.png": { b64: "", ct: "image/png" },
  "/icons/icon-128x128.png": { b64: "", ct: "image/png" },
  "/icons/icon-144x144.png": { b64: "", ct: "image/png" },
  "/icons/icon-152x152.png": { b64: "", ct: "image/png" },
  "/icons/icon-192x192.png": { b64: "", ct: "image/png" },
  "/icons/icon-384x384.png": { b64: "", ct: "image/png" },
  "/icons/icon-512x512.png": { b64: "", ct: "image/png" },
  "/icons/icon-maskable-512x512.png": { b64: "", ct: "image/png" },
  "/.well-known/assetlinks.json": { b64: "W3sKICAicmVsYXRpb24iOiBbImRlbGVnYXRlX3Blcm1pc3Npb24vY29tbW9uLmhhbmRsZV9hbGxfdXJscyJdLAogICJ0YXJnZXQiOiB7CiAgICAibmFtZXNwYWNlIjogImFuZHJvaWRfYXBwIiwKICAgICJwYWNrYWdlX25hbWUiOiAiYXBwLnNha2FuLm1kIiwKICAgICJzaGEyNTZfY2VydF9maW5nZXJwcmludHMiOiBbXQogIH0KfV0=", ct: "application/json" }
};


export default async function handler(req, res) {
  res.setHeader('access-control-allow-origin', '*');
  res.setHeader('access-control-allow-methods', 'GET,POST,PUT,OPTIONS');
  res.setHeader('access-control-allow-headers', 'authorization, content-type');
  if (req.method === 'OPTIONS') { res.status(204).end(); return; }

  const pathname = '/' + (Array.isArray(req.query.path) ? req.query.path.join('/') : req.query.path || '');

  // Serve PWA static assets
  if (ASSETS[pathname]) {
    const { b64, ct } = ASSETS[pathname];
    const buf = Buffer.from(b64, 'base64');
    const cc = ct.startsWith('image/') ? 'public, max-age=86400' : 'public, max-age=3600, must-revalidate';
    res.setHeader('content-type', ct);
    res.setHeader('cache-control', cc);
    res.status(200).send(buf);
    return;
  }

  // Serve HTML shell for root
  if (req.method === 'GET' && pathname === '/') {
    res.setHeader('content-type', 'text/html; charset=utf-8');
    res.status(200).send(PAGE);
    return;
  }

  // API routes — strip 'api' prefix if present (from passthrough rewrites)
  let path = [].concat(req.query.path || []);
  if (path[0] === 'api') path = path.slice(1);
  const token = (req.headers.authorization || '').replace(/^Bearer\s+/i, '') || null;
  const body = (req.body && typeof req.body === 'object') ? req.body : {};
  const { status, body: out } = await handle({ method: req.method, path, body, token });
  res.status(status).json(out);
}
